INSERT INTO "Review" ("id", "userId", "name", "educationalInstitution", "rating", "text", "isPublished", "createdAt") VALUES
('cmp67i07m05o5lk9cgdai6fh1', 'cmp5mtbp6002ugnh8bi6op4fv', 'Колодезников Александр', 'ГАПОУ «ЯКСИТ», группа ОИБ-25, 1 курс', '5', 'Отличный порядок тем: от паролей до разборов. Практика после лекций — то, что нужно. Курс завершил, сертификатом доволен, преподавателю показал без стыда.', 't', '2026-04-12 05:40:37.311'),
('cmp67i07n05o7lk9c47a51rwe', 'cmp5mtbp9002xgnh83b5fh40u', 'Макаров Ариан', 'ГАПОУ «ЯКСИТ», группа ОИБ-25, 1 курс', '5', 'Отличный итог для второго курса: и расследование, и «собрать картину» по логам — близко к тому, что обсуждаем на парах. Курс полностью прошёл.', 't', '2026-04-14 05:55:53.462'),
('cmp67i07n05o9lk9cni4zc0we', 'cmp5mtbpb0030gnh8vaeb0zvm', 'Мархеев Семен', 'ГАПОУ «ЯКСИТ», группа ОИБ-25, 1 курс', '5', 'Сильная практическая часть — после неё теория «ложится» в голову. Закрыл всё, сертификатом доволен. Рекомендую потоку.', 't', '2026-04-14 02:25:38.126'),
('cmp67i07x05pblk9cdt05i4ad', 'cmp5n9djx004fgnmm1aae25ty', 'Алексеев Габей', 'ГАПОУ «ЯКСИТ», группа ИСИП-25, 1 курс', '4', 'Хороший баланс теории и проверок. Все модули закрыл, к сертификату претензий нет. Звезду снял за то, что мобильная вёрстка местами прыгает.', 't', '2026-04-12 22:25:27.3'),
('cmp67i07x05pdlk9cp2qdco63', 'cmp5n9dk3004ignmmssz1cpm2', 'Алексеев Милан', 'ГАПОУ «ЯКСИТ», группа ИСИП-25, 1 курс', '4', 'Удобно совмещать с работой: чёткие дедлайны по модулям не дают забросить. Сертификат получил. Минус — иногда долгая загрузка страниц, на контент не влияет.', 't', '2026-04-12 21:49:52.508'),
('cmp67i06305iblk9ccy7j5jx0', 'cmp66xir000exlktg766yi654', 'Варламов Никита Андреевич', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-23, 3 курс', '5', 'Отличный порядок тем: от паролей до разборов. Практика после лекций — то, что нужно. Курс завершил, сертификатом доволен, преподавателю показал без стыда.', 't', '2026-04-10 21:49:08.501'),
('cmp67i07q05ojlk9c0bh3dbk5', 'cmp5mtbpm003cgnh8ygmwgagf', 'Оконешников Антон', 'ГАПОУ «ЯКСИТ», группа ОИБ-25, 1 курс', '2', 'Дошёл до конца из-за зачёта. Полезные вещи есть, но подача местами сухая. Сертификат не компенсирует ощущение «протёрпел».', 't', '2026-04-11 02:07:05.746'),
('cmp67i07q05ollk9cs45afjqu', 'cmp5mtbpo003fgnh8u0wu3kum', 'Павлов Виктор', 'ГАПОУ «ЯКСИТ», группа ОИБ-25, 1 курс', '5', 'Очень понравилось, что нельзя «прокликать» практику бездумно — проверка реально заставляет думать. Курс полностью прошёл, сертификатом доволен.', 't', '2026-04-12 08:23:31.203'),
('cmp67i07t05oxlk9cqdn6ckt1', 'cmp5mtbpw003xgnh8ovdexqxb', 'Слепцов Иннокентий', 'ГАПОУ «ЯКСИТ», группа ОИБ-25, 1 курс', '5', 'Очно на парах часто не хватает времени на «глубину» — здесь как раз она есть. Все модули закрыл, сертификат показал куратору. Топ.', 't', '2026-04-12 07:01:58.587'),
('cmp67i07r05onlk9c1ylh9q3p', 'cmp5mtbpq003ignh8gl9mknal', 'Павлов Данил', 'ГАПОУ «ЯКСИТ», группа ОИБ-25, 1 курс', '5', 'Заочно учиться непросто, но здесь всё разложено по полочкам: понятно, что делать каждый день. Курс завершил, сертификат забрал — горжусь.', 't', '2026-04-11 22:20:23.184'),
('cmp67i07r05oplk9clm1is4jz', 'cmp5mtbps003lgnh894v26jdt', 'Прокопьев Айаан', 'ГАПОУ «ЯКСИТ», группа ОИБ-25, 1 курс', '4', 'Как программисту, зашло сочетание «теория + руки». Прошёл полностью. Сертификат пригодится. Не пять звёзд только из‑за пары опечаток в заданиях.', 't', '2026-04-12 06:15:01.445'),
('cmp67i07s05orlk9cr84ei0bl', 'cmp5mtbpt003ognh8ta6hy8ay', 'Реев Пётр', 'ГАПОУ «ЯКСИТ», группа ОИБ-25, 1 курс', '2', 'Курс в итоге закончил, но тянулось тяжело: местами слишком плотно по тексту, а обратная связь по практике шла не так быстро, как хотелось. На троечку тянет, не больше.', 't', '2026-04-13 09:38:06.726'),
('cmp67i07s05otlk9c1fxj6s4s', 'cmp5mtbpu003rgnh8inkzxz99', 'Семенов Максим', 'ГАПОУ «ЯКСИТ», группа ОИБ-25, 1 курс', '2', 'Сертификат есть, но вовлечение среднее: часть модулей ощущались как «прочитай и ответь». Для галочки подойдёт.', 't', '2026-04-09 01:56:12.494'),
('cmp67i07t05ovlk9c4i1889mo', 'cmp5mtbpv003ugnh8xm86cmhh', 'Слепцов Далер', 'ГАПОУ «ЯКСИТ», группа ОИБ-25, 1 курс', '5', 'Очень понятная траектория, не расползается «водой». Дошёл до конца быстрее, чем ожидал. Сертификат — плюс к мотивации дальше копать тему.', 't', '2026-04-10 23:37:32.501'),
('cmp67i07u05ozlk9cy1o3nnz3', 'cmp5mtbpx0040gnh8r8mk47e9', 'Смирников Николай', 'ГАПОУ «ЯКСИТ», группа ОИБ-25, 1 курс', '3', 'В целом ок: прошёл, получил сертификат. Иногда не хватало короткого резюме после длинной лекции. Для базы по ИБ — нормально.', 't', '2026-04-14 12:30:23.991'),
('cmp67i07u05p1lk9c39755ez1', 'cmp5mtbpy0043gnh8xglwrrbh', 'Соловьев Айаал', 'ГАПОУ «ЯКСИТ», группа ОИБ-25, 1 курс', '4', 'Хорошо легло на первый курс: не перегружает, но и не «детский сад». Сертификат получил. Звезду снял за пару формулировок в тестах.', 't', '2026-04-14 07:41:45.782'),
('cmp67i07v05p5lk9cmiiyve91', 'cmp5mtbq00046gnh89cptztxh', 'Уарова Сардаана', 'ГАПОУ «ЯКСИТ», группа ОИБ-25, 1 курс', '4', 'Хорошо легло на первый курс: не перегружает, но и не «детский сад». Сертификат получил. Звезду снял за пару формулировок в тестах.', 't', '2026-04-11 03:09:18.347'),
('cmp67i07w05p7lk9c76k4c67p', 'cmp5mtbq10049gnh8e0tkhedu', 'Шабалин Сергей', 'ГАПОУ «ЯКСИТ», группа ОИБ-25, 1 курс', '5', 'Для заочного формата — очень достойно: и структура, и проверка практики. Закрыл все модули, сертификатом доволен, буду использовать в резюме.', 't', '2026-04-14 08:16:45.451'),
('cmp67i07w05p9lk9cyy7yncwb', 'cmp5mtbq2004cgnh8crnv1zab', 'Шилов Ньургун', 'ГАПОУ «ЯКСИТ», группа ОИБ-25, 1 курс', '2', 'Сертификат получил, но вовлечённость просела к середине: много текста, мало «быстрых побед». Для обязательной программы сойдёт, сам бы не выбрал.', 't', '2026-04-09 01:01:37.485'),
('cmp67i08705qhlk9cxj1hj48w', 'cmp5n9dkz0060gnmmi2aenm4w', 'Попова Карина', 'ГАПОУ «ЯКСИТ», группа ИСИП-25, 1 курс', '2', 'Дошёл до сертификата, но опыт спорный: часть формулировок сухая, а ожидания по времени на практику занижены. Для галочки сойдёт, восторгом не делюсь.', 't', '2026-04-14 00:29:19.596'),
('cmp67i06405iflk9ctkgh4xun', 'cmp66xir300f0lktgupnp6ksp', 'Владимиров Гавриил Александрович', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-23, 3 курс', '3', 'Нормально для обязательного блока: база по ИБ закрыта, сертификат выдали. Без «вау», но претензий к честности курса нет.', 't', '2026-04-12 05:03:16.862'),
('cmp67i08005pnlk9cvp9q3ho7', 'cmp5n9dkf004xgnmmtp4r1c03', 'Васильев Ярослав', 'ГАПОУ «ЯКСИТ», группа ИСИП-25, 1 курс', '3', 'Прошёл полностью, документ на руках. Нормальный уровень, без лишней воды. Хотелось бы чуть больше визуализации в лекциях.', 't', '2026-04-11 20:48:41.648'),
('cmp67i08105prlk9c27naft7j', 'cmp5n9dkh0050gnmmsx5jycai', 'Габышев Андрей', 'ГАПОУ «ЯКСИТ», группа ИСИП-25, 1 курс', '4', 'Хороший рабочий курс: и лекции, и задания, и итоговый документ. Отняла балл только то, что к концу устала от однотипных формулировок в подсказках, но по содержанию всё честно и по делу.', 't', '2026-04-12 04:13:24.258'),
('cmp67i08105ptlk9cny5010cv', 'cmp5n9dkj0053gnmmax0boc6c', 'Иванов Эдуард', 'ГАПОУ «ЯКСИТ», группа ИСИП-25, 1 курс', '5', 'Заочно учиться непросто, но здесь всё разложено по полочкам: понятно, что делать каждый день. Курс завершил, сертификат забрал — горжусь.', 't', '2026-04-10 10:16:27.285'),
('cmp67i08205pvlk9c1mw8lm61', 'cmp5n9dkl0056gnmm7nv1eb0s', 'Карамзин Вадим', 'ГАПОУ «ЯКСИТ», группа ИСИП-25, 1 курс', '3', 'Закрыл все модули, документ получил. По сути всё ок, но местами казалось затянуто. Для базового понимания ИБ на твёрдую «четвёрку» не хватило яркости примеров.', 't', '2026-04-09 10:40:04.5');